// completedBeforeUpdate reports whether the user passed this challenge only
// under an earlier version of the course content: at least one passing
// submission, all of them stamped with a variant_version older than the
// variant's current one. A pass at the current version means their work is
// up to date, so no notice.
func completedBeforeUpdate(submissions []domain.Submission, currentVersion int) bool {
	passedOlder := false
	for _, s := range submissions {
		if s.Status == "passed" {
			if s.VariantVersion >= currentVersion {
				return false
			}
			passedOlder = true
		}
	}
	return passedOlder
}

// editorCode picks the code to prefill the editor with: the user's latest
// submission if they have one, otherwise the challenge's starter code.
func editorCode(latestCode, starterCode string) string {
	if latestCode != "" {
		return latestCode
	}
	return starterCode
}

